INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('507', '<p><strong>Travelling with children : Tips, trick and good ideas</strong></p><p><u>Books</u><br/>If your child suffers from travel sickness, try to avoid books as . . . <strong>(9)</strong> . . . in the car. However, for children who travel well, a coloring book and a set of crayons, or a picture book, will keep them entertained on long . . . (10) . . .</p><p><u>Foods</u><br/>Try not to pack cans of fizzy drinks or chocolates as . . . (11) . . . to eat in the car. Keep a damp cloth in a plastic bag or box to . . . (12) . . . their faces and fingers and a plastic bag for wrappers the other . . . (13) . . .</p><p><strong>9. เลือกคำตอบเพื่อเติมลงในช่องว่าง (9)</strong></p>', '{"A":"entertainment","B":"supplement","C":"education","D":"exercise"}', 'A', '<p><strong>ตอบ 1) entertainment (ความบันเทิง)</strong></p><p>จากบริบท "หลีกเลี่ยงการใช้หนังสือเป็น...ในรถ" คำที่เหมาะสมที่สุดคือ ความบันเทิง (entertainment)</p>', 'ก.พ.', 'ภาษาอังกฤษ', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["คำศัพท์ (Vocabulary)"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('508', '<p><strong>Travelling with children : Tips, trick and good ideas</strong></p><p><u>Books</u><br/>If your child suffers from travel sickness, try to avoid books as . . . (9) . . . in the car. However, for children who travel well, a coloring book and a set of crayons, or a picture book, will keep them entertained on long . . . <strong>(10)</strong> . . .</p><p><u>Foods</u><br/>Try not to pack cans of fizzy drinks or chocolates as . . . (11) . . . to eat in the car. Keep a damp cloth in a plastic bag or box to . . . (12) . . . their faces and fingers and a plastic bag for wrappers the other . . . (13) . . .</p><p><strong>10. เลือกคำตอบเพื่อเติมลงในช่องว่าง (10)</strong></p>', '{"A":"vacation","B":"wanderings","C":"journeys","D":"roaming"}', 'C', '<p><strong>ตอบ 3) journeys (การเดินทาง)</strong></p><p>จากบริบท "ทำให้พวกเขาเพลิดเพลินใน...ที่ยาวนาน" คำที่เข้ากับบริบทการนั่งรถคือ การเดินทาง (journeys)</p>', 'ก.พ.', 'ภาษาอังกฤษ', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["คำศัพท์ (Vocabulary)"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('509', '<p><strong>Travelling with children : Tips, trick and good ideas</strong></p><p><u>Books</u><br/>If your child suffers from travel sickness, try to avoid books as . . . (9) . . . in the car. However, for children who travel well, a coloring book and a set of crayons, or a picture book, will keep them entertained on long . . . (10) . . .</p><p><u>Foods</u><br/>Try not to pack cans of fizzy drinks or chocolates as . . . <strong>(11)</strong> . . . to eat in the car. Keep a damp cloth in a plastic bag or box to . . . (12) . . . their faces and fingers and a plastic bag for wrappers the other . . . (13) . . .</p><p><strong>11. เลือกคำตอบเพื่อเติมลงในช่องว่าง (11)</strong></p>', '{"A":"meals","B":"appetizers","C":"snacks","D":"breakfast"}', 'C', '<p><strong>ตอบ 3) snacks (ขนม/อาหารว่าง)</strong></p><p>ช็อคโกแลตและน้ำอัดลม ถือเป็นอาหารว่างหรือขนม (snacks) ไม่ใช่มื้ออาหารหลัก (meals)</p>', 'ก.พ.', 'ภาษาอังกฤษ', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["คำศัพท์ (Vocabulary)"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('510', '<p><strong>Travelling with children : Tips, trick and good ideas</strong></p><p><u>Books</u><br/>If your child suffers from travel sickness, try to avoid books as . . . (9) . . . in the car. However, for children who travel well, a coloring book and a set of crayons, or a picture book, will keep them entertained on long . . . (10) . . .</p><p><u>Foods</u><br/>Try not to pack cans of fizzy drinks or chocolates as . . . (11) . . . to eat in the car. Keep a damp cloth in a plastic bag or box to . . . <strong>(12)</strong> . . . their faces and fingers and a plastic bag for wrappers the other . . . (13) . . .</p><p><strong>12. เลือกคำตอบเพื่อเติมลงในช่องว่าง (12)</strong></p>', '{"A":"rub","B":"wipe","C":"touch","D":"scrub"}', 'B', '<p><strong>ตอบ 2) wipe (เช็ด)</strong></p><p>จากบริบท "เตรียมผ้าเปียกเพื่อ...หน้าและนิ้วมือ" คำกริยาที่เหมาะสมกับผ้าเปียกคือ เช็ด (wipe)</p>', 'ก.พ.', 'ภาษาอังกฤษ', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["คำศัพท์ (Vocabulary)"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('511', '<p><strong>Travelling with children : Tips, trick and good ideas</strong></p><p><u>Books</u><br/>If your child suffers from travel sickness, try to avoid books as . . . (9) . . . in the car. However, for children who travel well, a coloring book and a set of crayons, or a picture book, will keep them entertained on long . . . (10) . . .</p><p><u>Foods</u><br/>Try not to pack cans of fizzy drinks or chocolates as . . . (11) . . . to eat in the car. Keep a damp cloth in a plastic bag or box to . . . (12) . . . their faces and fingers and a plastic bag for wrappers the other . . . <strong>(13)</strong> . . .</p><p><strong>13. เลือกคำตอบเพื่อเติมลงในช่องว่าง (13)</strong></p>', '{"A":"boxes","B":"dirt","C":"cans","D":"trash"}', 'D', '<p><strong>ตอบ 4) trash (ขยะ)</strong></p><p>จากบริบท "เตรียมถุงพลาสติกไว้สำหรับใส่ห่อขนมและ...อื่นๆ" สิ่งที่ต้องทิ้งรวมกับห่อขนมคือ ขยะ (trash)</p>', 'ก.พ.', 'ภาษาอังกฤษ', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["คำศัพท์ (Vocabulary)"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('512', '<p><strong>14. The manager has no objection to . . . . the meeting since his daughter is ill.</strong></p>', '{"A":"John not attend","B":"John does not attend","C":"John''s not attending","D":"John not to attend"}', 'C', '<p><strong>ตอบ 3) John''s not attending</strong></p><p>คำแปล : ผู้จัดการไม่คัดค้านการที่จอห์นไม่เข้าประชุม เพราะลูกสาวของเขาป่วย<br/>สังเกตคำว่า objection to . . . ต้องตามด้วยคำนามหรือ gerund (v.ing) ซึ่งมีเพียงตัวเลือกเดียวที่มี -ing คือตัวเลือกที่ 3</p>', 'ก.พ.', 'ภาษาอังกฤษ', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["ไวยากรณ์ (Grammar)"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('513', '<p><strong>15. As soon as the examinees . . . . the test, the score . . . .</strong></p>', '{"A":"finish, will report","B":"will finish, will report","C":"finish, will be reported","D":"will finish, will be report"}', 'C', '<p><strong>ตอบ 3) finish, will be reported</strong></p><p>คำแปล : ทันทีที่ผู้เข้าสอบทำแบบทดสอบเสร็จ คะแนนจะถูกรายงานทันที<br/>ประโยคแรก "As soon as the examinees . . . . the test" เป็น present simple จึงใช้คำว่า finish<br/>ประโยคที่สอง "the score . . . ." เป็น passive voice รูปประโยคคือ v. to be + v.3 จึงใช้คำว่า will be reported</p>', 'ก.พ.', 'ภาษาอังกฤษ', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["ไวยากรณ์ (Grammar)"]', '2559');
